  1→// This is sample on how to consume service tree oData Apis using http client.
  2→
  3→using Microsoft.Tree.Client.Authentication;
  4→
  5→namespace TreeHttpClient
  6→{
  7→    using System;
  8→    using Newtonsoft.Json.Linq;
  9→    using System.Threading.Tasks;
 10→    using System.Net.Http;
 11→    using Newtonsoft.Json;
 12→    using System.Text;
 13→    class Program
 14→    {
 15→        public static string ProdEndpoint = "https://servicetree.msftcloudes.com/cert/api";
 16→        public static string PPEEndpoint = "https://servicetreeppe.msftcloudes.com/cert/api";
 17→
 18→        private static string CurrentEndpoint = ProdEndpoint;
 19→
 20→
 21→        //If you don't have a thumbprint, here are the instructions to get one by following instructions at
 22→        // https://microsoft.sharepoint.com/teams/WAG/EngSys/ServiceMgmt/ServiceTree/_layouts/15/start.aspx#/SitePages/Cert-Based%20Authentication.aspx
 23→        public const string ThumbPrint = "fbd2f1a5a5865ddfbb09b9243221d56777ab849f";
 24→        private static CertificateContext authenticationContext;
 25→
 26→        static void Main()
 27→        {
 28→            authenticationContext = new CertificateContext(new Uri(CurrentEndpoint), ThumbPrint);
 29→
 30→            ListAllServicesAtAllLevelsAsync().GetAwaiter().GetResult();
 31→
 32→            //below guid is what you see as Service Id in https://servicetree.msftcloudes.com UI.
 33→            GetMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea")).GetAwaiter().GetResult();
 34→
 35→            //Properties here are listed in ServiceMetadata entity in /api/$metadata
 36→            var metadata = new
 37→            {
 38→                //list of possible values can be seen in api/$metadata for AzureCloudEnum
 39→                AzureCloud = "Public",
 40→                //list of possible values can be known by querying all the metadata definitions at api/ServiceMetadataDefinitions
 41→                MetadataDefinitionId = "Contact_DevOwner",
 42→                Contact_DevOwner = "chetanra-test"
 43→            };
 44→            AddMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"), metadata).GetAwaiter().GetResult();
 45→        }
 46→
 47→        /// <summary>
 48→        /// This demons retrieving a flat list of services, microservices and components from the service tree.
 49→        /// </summary>
 50→        public static async Task ListAllServicesAtAllLevelsAsync()
 51→        {
 52→            //url is case sensitive
 53→            var url = string.Format("{0}/ServiceHierarchy", ProdEndpoint);
 54→
 55→            var client = authenticationContext.GetHttpClient();
 56→
 57→            var response = await client.GetStringAsync(url);
 58→            dynamic responseMessage = JObject.Parse(response);
 59→
 60→            dynamic serviceHierarchy = responseMessage["value"];
 61→
 62→            foreach (var item in serviceHierarchy)
 63→            {
 64→                //Get to know all the properties exposed by ServiceHierarchy by going to /api/$metadata and searchign for string "EntityType Name="ServiceHierarchy""
 65→                Console.WriteLine("{0} --- {1} --- {2}", item["Name"], item["NodeType"], item["Id"]);
 66→            }
 67→        }
 68→
 69→
 70→        /// <summary>
 71→        /// Get Metadata for a service, microservice or component
 72→        /// </summary>
 73→        public static async Task<object> GetMetadataAsync(Guid serviceHierarchyId)
 74→        {
 75→            //url is case sensitive
 76→            var url = string.Format("{0}/ServiceHierarchy({1})/ServiceTree.GetMetadata", ProdEndpoint, serviceHierarchyId);
 77→
 78→            var client = authenticationContext.GetHttpClient();
 79→
 80→            var response = await client.GetStringAsync(url);
 81→
 82→            dynamic responseMessage = JObject.Parse(response);
 83→
 84→            dynamic serviceMetadataList = responseMessage["value"];
 85→
 86→            foreach (var item in serviceMetadataList)
 87→            {
 88→                //Get to know all the properties exposed by ServiceMetadata by going to /api/$metadata and searchign for string "EntityType Name="ServiceMetadata""
 89→                Console.WriteLine("{0} --- {1}", item["Id"], item["MetadataDefinitionId"]);
 90→            }
 91→
 92→            return serviceMetadataList;
 93→        }
 94→
 95→        /// <summary>
 96→        /// Sets Metadata for a service, microservice or component
 97→        /// You need to be an admin of the service that you are setting the metadata on
 98→        /// Or admin of the service that owns the metadata definition
 99→        /// </summary>
100→        public static async Task<object> AddMetadataAsync(Guid serviceHierarchyId, object metadata)
101→        {
102→            //url is case sensitive
103→            var url = string.Format("{0}/ServiceHierarchy({1})/ServiceTree.AddMetadata", ProdEndpoint, serviceHierarchyId);
104→
105→            var client = authenticationContext.GetHttpClient();
106→
107→            var response = await client.PostAsync(url, new StringContent(JsonConvert.SerializeObject(new { ServiceMetadata = metadata }), Encoding.UTF8, "application/json") as HttpContent);
108→
109→            var responseString = await response.Content.ReadAsStringAsync();
110→
111→            dynamic jsonResponse = JObject.Parse(responseString);
112→
113→            //Get to know all the properties exposed by ServiceMetadata by going to /api/$metadata and searchign for string "EntityType Name="ServiceMetadata""
114→            Console.WriteLine("{0} --- {1}", jsonResponse["Id"], jsonResponse["Contact_DevOwner"]);
115→
116→            return jsonResponse;
117→        }
118→    }
119→}
