20→
21→
22→        //If you don't have a thumbprint, here are the instructions to get one by following instructions at
23→        // https://microsoft.sharepoint.com/teams/WAG/EngSys/ServiceMgmt/ServiceTree/_layouts/15/start.aspx#/SitePages/Cert-Based%20Authentication.aspx
24→        public const string ThumbPrint = "fbd2f1a5a5865ddfbb09b9243221d56777ab849f";
25→
26→        private static ServiceTreeContext odataClient;
27→        private static CertificateContext authenticationContext;
28→
29→        static void Main(string[] args)
30→        {
31→            authenticationContext = new CertificateContext(new Uri(CurrentEndpoint), ThumbPrint);
32→
33→            SetupOdataClient();
34→
35→            var hierarchyNodes = ListAllServicesAtAllLevels();
36→
37→            var metadataList = GetMetadata(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"));
38→
39→            var metadata = new ServiceMetadata
40→            {
41→                AzureCloud = AzureCloudEnum.Public,
42→                //list of possible values can be known by querying all the metadata definitions at api/ServiceMetadataDefinitions
43→                MetadataDefinitionId = "Contact_DevOwner",
44→                //Service metadata is an open type, client code needs to expand 
45→                //see link for mode details http://blogs.msdn.com/b/odatateam/archive/2014/04/30/how-to-use-open-type-in-odata.aspx
46→                //ServiceMetadata.cs for exapnaded dev owner.
47→                Contact_DevOwner = "chetanra-test"
48→            };
49→            var updatedMetadata = AddMetadataAsync(new Guid("ca677e7c-00fc-4bf7-bdff-2e619aacb1ea"), metadata).GetAwaiter().GetResult();
50→        }
51→
52→        ///<summary>
53→        ///Get Metadata for a service, microservice or component
54→        ///</summary>
55→        public static IEnumerable<ServiceMetadata> GetMetadata(Guid serviceHierarchyId)
56→        {
57→            var metadata = odataClient.ServiceHierarchy.ByKey(serviceHierarchyId).GetMetadata();
58→
59→            foreach (var item in metadata)
60→            {
61→                Console.WriteLine(item.MetadataDefinitionId);
62→            }
63→
64→            return metadata.ToList();
65→        }
66→
67→        /// <summary>
68→        /// Sets Metadata for a service, microservice or component
69→        /// You need to be an admin of the service that you are setting the metadata on
70→        /// Or admin of the service that owns the metadata definition
71→        /// </summary>
72→        public static async Task<ServiceMetadata> AddMetadataAsync(Guid serviceHierarchyId, ServiceMetadata metadata)
73→        {
74→            var updatedmetadata = await odataClient.ServiceHierarchy.ByKey(serviceHierarchyId).AddMetadata(metadata).GetValueAsync();
75→            return updatedmetadata;
76→        }
77→
78→        /// <summary>
79→        /// This demons retrieving a flat list of services, microservices and components from the service tree.
80→        /// </summary>
81→        public static IEnumerable<ServiceHierarchy> ListAllServicesAtAllLevels()
82→        {
83→            foreach (var node in odataClient.ServiceHierarchy)
84→            {
85→                Console.WriteLine("{0} --- {1} --- {2}", node.Name, node.NodeType, node.Id);
86→            }
87→
88→            return odataClient.ServiceHierarchy.Where(node => node.NodeType == "Service").ToList();
89→        }
90→
91→        private static void SetupOdataClient()
92→        {
93→            odataClient = new ServiceTreeContext(authenticationContext.ApiUri);
94→            odataClient.SendingRequest2 += authenticationContext.OnSendingRequestAddAuthenticationHeaders;
95→        }
96→    }
97→}
